principle.example:

# OpenSearch hybrid search
def hybrid_search(query: str, top_k: int = 10):
    # Generate query embedding
    query_vector = embeddings.embed_query(query)

    # Hybrid query combining k-NN and BM25
    search_query = {
        "size": top_k,
        "query": {
            "bool": {
                "should": [
                    {
                        "knn": {
                            "embedding": {
                                "vector": query_vector,
                                "k": top_k
                            }
                        }
                    },
                    {
                        "match": {
                            "text": {
                                "query": query,
                                "boost": 0.3  # Weight keyword search lower
                            }
                        }
                    }
                ]
            }
        }
    }

    results = opensearch_client.search(index="knowledge_base", body=search_query)
    return results['hits']['hits']

