from fastmcp import FastMCP

mcp = FastMCP("RAG Knowledge Base")

@mcp.tool()
def ingest_documents(
    source_path: str,
    chunk_size: int = 400,
    chunk_overlap: int = 50
) -> str:
    """Ingest documents into the RAG knowledge base"""
    try:
        # Load documents
        loader = DirectoryLoader(source_path)
        documents = loader.load()

        # Chunk documents
        splitter = RecursiveCharacterTextSplitter(
            chunk_size=chunk_size,
            chunk_overlap=chunk_overlap
        )
        chunks = splitter.split_documents(documents)

        # Generate embeddings
        vectors = embeddings.embed_documents([c.page_content for c in chunks])

        # Store in vector database
        vector_db.add_documents(chunks, vectors)

        return f"Successfully ingested {len(chunks)} chunks from {len(documents)} documents"
    except Exception as e:
        return f"Error ingesting documents: {str(e)}"

@mcp.tool()
def search_knowledge_base(
    query: str,
    top_k: int = 5,
    filters: dict = None
) -> list:
    """Search the RAG knowledge base"""
    try:
        # Generate query embedding
        query_vector = embeddings.embed_query(query)

        # Search vector database
        results = vector_db.search(
            query_vector,
            top_k=top_k,
            filter=filters
        )

        return [
            {
                "text": doc.page_content,
                "metadata": doc.metadata,
                "score": score
            }
            for doc, score in results
        ]
    except Exception as e:
        return [{"error": str(e)}]

@mcp.tool()
def ask_question(
    question: str,
    top_k: int = 5,
    include_sources: bool = True
) -> dict:
    """Ask a question using RAG"""
    try:
        # Retrieve relevant documents
        docs = search_knowledge_base(question, top_k)

        # Generate answer
        answer = generate_answer(question, docs)

        result = {"answer": answer}
        if include_sources:
            result["sources"] = [
                {
                    "text": doc["text"][:200] + "...",
                    "source": doc["metadata"].get("source"),
                    "score": doc["score"]
                }
                for doc in docs
            ]

        return result
    except Exception as e:
        return {"error": str(e)}
